def process_graph(graph_data):
    graph_copy = graph_data.copy()
    agg_node_id = None
    for node_id, attrs in graph_copy.nodes(data=True):
        if attrs.get('name') == 'ju1.a3.m1' and 'EK_AGG_BLOCK' in attrs.get('type', []):
            agg_node_id = node_id
            break

    result_data = []
    if agg_node_id is not None:
        child_nodes = []
        for neighbor in graph_copy.successors(agg_node_id):
            edge_data = graph_copy.get_edge_data(agg_node_id, neighbor)
            if edge_data and 'RK_CONTAINS' in edge_data.get('type', []):
                child_nodes.append(neighbor)

        capacity_list = []
        for child_id in child_nodes:
            stack = [child_id]
            visited = set()
            total_capacity = 0
            while stack:
                current = stack.pop()
                if current in visited:
                    continue
                visited.add(current)
                node_attrs = graph_copy.nodes[current]
                if 'EK_PORT' in node_attrs.get('type', []):
                    total_capacity += node_attrs.get('physical_capacity_bps', 0)
                for succ in graph_copy.successors(current):
                    edge_data_child = graph_copy.get_edge_data(current, succ)
                    if edge_data_child and 'RK_CONTAINS' in edge_data_child.get('type', []):
                        stack.append(succ)
            child_name = graph_copy.nodes[child_id]['name']
            capacity_list.append((child_name, total_capacity))

        capacity_list.sort(key=lambda x: x[1], reverse=True)
        result_data = [[name, cap] for name, cap in capacity_list]

    graph_json = nx.readwrite.json_graph.node_link_data(graph_copy)
    return {
        'type': 'list',
        'data': result_data,
        'updated_graph': graph_json
    }

